var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Breaking change 1 – ValidateScopes (now on by default in Development)
// A scoped service cannot be resolved from a singleton. Register ICacheService as scoped,
// or give it its own IServiceScopeFactory. Keeping it scoped is the simplest correct fix.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Breaking change 2 – HttpClientFactory now uses SocketsHttpHandler by default.
// Casting PrimaryHandler to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler to supply the exact handler type.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
// Breaking change 3 – HttpClientFactory redacts all header values in Trace-level logs.
// Explicitly allowlist the non-sensitive headers you need to see for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Cache-Control"
        && h != "Content-Type"
        && h != "Accept"));
// Breaking change 4 – ForwardedHeadersMiddleware now ignores X-Forwarded-* headers
// from proxies not listed in KnownProxies / KnownNetworks.
// Add your trusted reverse-proxy address(es) here.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

